    mathSolution: "Converting between List and Array.",
    codeSolution: "using System;\nusing System.Collections.Generic;\n\nclass Program\n{\n    static void Main()\n    {\n        // Array to List\n        int[] array = new int[] { 1, 2, 3, 4, 5 };\n        List<int> listFromArray = new List<int>(array);\n        Console.WriteLine($\"Array to List: {string.Join(\", \", listFromArray)}\");\n        \n        // List to Array\n        List<string> fruits = new List<string> { \"Apple\", \"Banana\", \"Cherry\" };\n        string[] arrayFromList = fruits.ToArray();\n        Console.WriteLine($\"List to Array: {string.Join(\", \", arrayFromList)}\");\n        \n        // Modify array doesn't affect original list\n        arrayFromList[0] = \"Orange\";\n        Console.WriteLine($\"Original list still: {string.Join(\", \", fruits)}\");\n        \n        // List to Array with conversion\n        List<double> decimals = new List<double> { 1.1, 2.2, 3.3 };\n        double[] doubleArray = decimals.ToArray();\n        \n        // Array to List with LINQ\n        int[] moreNumbers = { 10, 20, 30, 40 };\n        List<int> listFromLinq = new List<int>(moreNumbers);\n        Console.WriteLine($\"Array to List (LINQ): {string.Join(\", \", listFromLinq)}\");\n    }\n}",
